import { useEffect, useMemo, useState } from "react";
import { useLocation } from "wouter";
import { BarChart3, CalendarDays } from "lucide-react";
import {
  Area,
  AreaChart,
  Bar,
  BarChart,
  CartesianGrid,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from "recharts";
import { calculatorRoutes } from "@/data/siteRoutes";
import { formatCurrencyValue } from "@/lib/currency";

type SchedulePoint = {
  month: number;
  payment: number;
  principal: number;
  interest: number;
  balance: number;
  paid: number;
};

type LoanInputs = {
  amount: number;
  rate: number;
  months: number;
  payment?: number;
};

const loanPaths = new Set(
  calculatorRoutes
    .filter((route) => /loan|mortgage|amortization|repayment|payment|debt|credit-card|refinance|lease/i.test(route.path))
    .map((route) => route.path),
);

function money(value: number) {
  return formatCurrencyValue(Number.isFinite(value) ? value : 0, { maximumFractionDigits: 0 });
}

function normalize(text: string) {
  return text.toLowerCase().replace(/[^a-z0-9]+/g, " ").trim();
}

function isVisible(element: Element) {
  const el = element as HTMLElement;
  return Boolean(el.offsetParent || el.getClientRects().length);
}

function labelForField(field: HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement) {
  const id = field.id ? CSS.escape(field.id) : "";
  const label =
    (id ? document.querySelector(`label[for="${id}"]`)?.textContent : "") ||
    (id ? document.querySelector(`label[for="${id}-slider"]`)?.textContent : "") ||
    field.closest("label")?.textContent ||
    field.parentElement?.querySelector("label")?.textContent ||
    field.getAttribute("aria-label") ||
    field.getAttribute("placeholder") ||
    field.name ||
    field.id ||
    "";
  return normalize(label);
}

function numericValue(field: HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement) {
  const value = field instanceof HTMLSelectElement ? field.value : field.value;
  const number = Number(String(value).replace(/[$,%\s,]+/g, ""));
  return Number.isFinite(number) ? number : undefined;
}

function collectNumericFields() {
  return Array.from(document.querySelectorAll("main input, main select"))
    .filter((field): field is HTMLInputElement | HTMLSelectElement =>
      field instanceof HTMLInputElement || field instanceof HTMLSelectElement,
    )
    .filter((field) => {
      if (!isVisible(field)) return false;
      if (field.closest("[data-amortization-visualizer], [data-calculation-history-root]")) return false;
      if (field instanceof HTMLInputElement && ["hidden", "file", "search", "button", "submit", "reset", "radio", "checkbox"].includes(field.type)) return false;
      return numericValue(field) !== undefined;
    })
    .map((field) => ({ label: labelForField(field), value: numericValue(field) ?? 0 }));
}

function findValue(fields: Array<{ label: string; value: number }>, matcher: RegExp) {
  return fields.find((field) => matcher.test(field.label))?.value;
}

function readLoanInputs(): LoanInputs | null {
  const fields = collectNumericFields();
  const homePrice = findValue(fields, /home price|property price|vehicle price|car price|asset value|purchase price|boat price/);
  const downPayment = findValue(fields, /down payment|deposit/) ?? 0;
  const explicitAmount = findValue(fields, /loan amount|mortgage amount|balance|principal|amount borrowed|current loan balance|remaining mortgage balance/);
  const amount = Math.max(0, (explicitAmount ?? (homePrice ? homePrice - downPayment : 0)));
  const rate = findValue(fields, /interest rate|annual rate|apr|current rate|new rate|mortgage rate|lease apr/) ?? 0;
  const years = findValue(fields, /term years|loan term|number of years|years|amortization period|remaining term/);
  const termMonths = findValue(fields, /term months|months|monthly payments|number of monthly payments/);
  const months = termMonths && termMonths > 12 ? termMonths : Math.round((years && years <= 100 ? years * 12 : termMonths || 0));
  const payment = findValue(fields, /monthly payment|current monthly payment|desired monthly payment/);

  if (amount <= 0 || rate < 0 || months <= 0) return null;
  return { amount, rate, months: Math.min(months, 600), payment };
}

function buildSchedule({ amount, rate, months, payment }: LoanInputs): SchedulePoint[] {
  const monthlyRate = rate / 100 / 12;
  const calculatedPayment = payment && payment > 0
    ? payment
    : monthlyRate
      ? (amount * monthlyRate * Math.pow(1 + monthlyRate, months)) / (Math.pow(1 + monthlyRate, months) - 1)
      : amount / months;
  const rows: SchedulePoint[] = [];
  let balance = amount;
  let paid = 0;

  for (let month = 1; month <= months && balance > 0.01; month += 1) {
    const interest = balance * monthlyRate;
    const principal = Math.min(Math.max(calculatedPayment - interest, 0), balance);
    const actualPayment = principal + interest;
    balance = Math.max(0, balance - principal);
    paid += principal;
    rows.push({ month, payment: actualPayment, principal, interest, balance, paid });
    if (principal <= 0 && month > 2) break;
  }

  return rows;
}

export default function AmortizationVisualizer() {
  const [location] = useLocation();
  const [inputs, setInputs] = useState<LoanInputs | null>(null);
  const [selectedMonth, setSelectedMonth] = useState(1);

  const isLoanPage = loanPaths.has(location);
  const schedule = useMemo(() => inputs ? buildSchedule(inputs) : [], [inputs]);
  const selected = schedule[Math.min(selectedMonth - 1, schedule.length - 1)];

  useEffect(() => {
    if (!isLoanPage) return;
    const refresh = () => setInputs(readLoanInputs());
    const timers = [250, 750, 1400].map((delay) => window.setTimeout(refresh, delay));
    const onInput = () => window.setTimeout(refresh, 80);
    document.addEventListener("input", onInput);
    document.addEventListener("change", onInput);
    refresh();

    return () => {
      timers.forEach((timer) => window.clearTimeout(timer));
      document.removeEventListener("input", onInput);
      document.removeEventListener("change", onInput);
    };
  }, [isLoanPage, location]);

  useEffect(() => {
    setSelectedMonth(1);
  }, [location, schedule.length]);

  if (!isLoanPage || !inputs || schedule.length < 2 || !selected) return null;

  const sampled = schedule.filter((point) => point.month === 1 || point.month === schedule.length || point.month % Math.max(1, Math.ceil(schedule.length / 72)) === 0);
  const stacked = schedule.slice(0, Math.min(schedule.length, 120));
  const totalInterest = schedule.reduce((sum, point) => sum + point.interest, 0);
  const totalPrincipal = schedule.reduce((sum, point) => sum + point.principal, 0);

  return (
    <section data-amortization-visualizer className="mx-auto max-w-3xl px-4 sm:px-6 py-6">
      <div className="rounded-2xl border border-border bg-card p-5 shadow-sm sm:p-6">
        <div className="mb-5 flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
          <div>
            <div className="mb-2 inline-flex items-center gap-2 rounded-full bg-sky-500/10 px-3 py-1 text-xs font-bold uppercase tracking-widest text-sky-600 dark:text-sky-400">
              <BarChart3 className="h-3.5 w-3.5" />
              Amortization Visualization
            </div>
            <h2 className="text-xl font-extrabold text-foreground">Principal vs interest over time</h2>
            <p className="mt-2 text-sm leading-relaxed text-muted-foreground">
              Drag the month slider or click a bar to inspect the exact payment split and remaining balance.
            </p>
          </div>
          <div className="rounded-xl border border-border bg-muted/30 px-4 py-3 text-sm">
            <p className="font-bold text-foreground">{money(inputs.amount)} loan</p>
            <p className="text-muted-foreground">{inputs.rate}% for {Math.round(inputs.months / 12)} years</p>
          </div>
        </div>

        <div className="h-72 w-full rounded-xl border border-border bg-background p-3">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={sampled} margin={{ left: 0, right: 8, top: 10, bottom: 0 }} onClick={(event) => {
              const month = Number(event?.activePayload?.[0]?.payload?.month);
              if (month) setSelectedMonth(month);
            }}>
              <CartesianGrid strokeDasharray="3 3" opacity={0.25} />
              <XAxis dataKey="month" tick={{ fontSize: 12 }} tickFormatter={(value) => `M${value}`} />
              <YAxis tick={{ fontSize: 12 }} tickFormatter={(value) => money(Number(value)).replace(".00", "")} width={72} />
              <Tooltip formatter={(value: number, name: string) => [money(value), name === "balance" ? "Balance" : name]} labelFormatter={(label) => `Month ${label}`} />
              <Area type="monotone" dataKey="balance" name="Balance" stroke="#0ea5e9" fill="#0ea5e9" fillOpacity={0.18} isAnimationActive />
            </AreaChart>
          </ResponsiveContainer>
        </div>

        <div className="mt-5">
          <label htmlFor="amortization-month-slider" className="mb-2 flex items-center justify-between gap-3 text-sm font-bold text-foreground">
            <span className="inline-flex items-center gap-2"><CalendarDays className="h-4 w-4" /> Month {selected.month}</span>
            <span>{money(selected.balance)} balance</span>
          </label>
          <input
            id="amortization-month-slider"
            type="range"
            min={1}
            max={schedule.length}
            value={Math.min(selectedMonth, schedule.length)}
            onChange={(event) => setSelectedMonth(Number(event.target.value))}
            className="pc-slider h-2 w-full cursor-pointer appearance-none rounded-full"
          />
        </div>

        <div className="mt-5 grid grid-cols-2 gap-3 sm:grid-cols-4">
          {[
            ["Payment", money(selected.payment)],
            ["Principal", money(selected.principal)],
            ["Interest", money(selected.interest)],
            ["Balance", money(selected.balance)],
          ].map(([label, value]) => (
            <div key={label} className="rounded-xl border border-border bg-accent/50 p-3 text-center">
              <p className="text-xs font-semibold text-muted-foreground">{label}</p>
              <p className="mt-1 text-lg font-extrabold text-foreground">{value}</p>
            </div>
          ))}
        </div>

        <div className="mt-5 h-64 w-full rounded-xl border border-border bg-background p-3">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={stacked} margin={{ left: 0, right: 8, top: 10, bottom: 0 }} onClick={(event) => {
              const month = Number(event?.activePayload?.[0]?.payload?.month);
              if (month) setSelectedMonth(month);
            }}>
              <CartesianGrid strokeDasharray="3 3" opacity={0.25} />
              <XAxis dataKey="month" tick={{ fontSize: 12 }} interval="preserveStartEnd" />
              <YAxis tick={{ fontSize: 12 }} tickFormatter={(value) => money(Number(value)).replace(".00", "")} width={72} />
              <Tooltip formatter={(value: number, name: string) => [money(value), name === "principal" ? "Principal" : "Interest"]} labelFormatter={(label) => `Month ${label}`} />
              <Bar dataKey="principal" stackId="payment" fill="#10b981" name="Principal" isAnimationActive />
              <Bar dataKey="interest" stackId="payment" fill="#ef4444" name="Interest" isAnimationActive />
            </BarChart>
          </ResponsiveContainer>
        </div>

        <div className="mt-4 grid grid-cols-1 gap-3 text-sm sm:grid-cols-2">
          <div className="rounded-xl border border-emerald-500/20 bg-emerald-500/10 p-3">
            <p className="font-bold text-emerald-700 dark:text-emerald-300">Total principal</p>
            <p className="text-muted-foreground">{money(totalPrincipal)} paid toward the original balance.</p>
          </div>
          <div className="rounded-xl border border-red-500/20 bg-red-500/10 p-3">
            <p className="font-bold text-red-700 dark:text-red-300">Total interest</p>
            <p className="text-muted-foreground">{money(totalInterest)} paid as borrowing cost.</p>
          </div>
        </div>
      </div>
    </section>
  );
}
